mapper.select:
SELECT
    id, line_no, scene_no, strategy_name, strategy_no, model, version, deploy_at, is_valid, is_delete
FROM strategy


        line_no = #{param.lineNo}


        AND scene_no = #{param.sceneNo}


        AND strategy_name like CONCAT(#{param.strategyName}, '%')


        AND strategy_no = #{param.strategyNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM strategy


        line_no = #{param.lineNo}


        AND scene_no = #{param.sceneNo}


        AND strategy_name like CONCAT(#{param.strategyName}, '%')


        AND strategy_no = #{param.strategyNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0
